import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Safety/webdav-site-access.md","filePath":"th-TH/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"th-TH/Safety/webdav-site-access.md"};function o(r,e,c,p,h,b){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>WebDAV setting ใน Security Settings ทำให้ ImgBed site ของคุณเป็น WebDAV endpoint</p><p>หลัง enable แล้ว คุณสามารถใช้ Windows, macOS, mobile file managers หรือ WebDAV-compatible client ใด ๆ เพื่อ browse, upload, delete และ manage ImgBed files เหมือน remote folder</p><p>นี่คือ WebDAV access entry ของ site แตกต่างจาก WebDAV storage channel ใน Upload Settings Upload channel ใช้ store files ใน third-party WebDAV service ส่วน setting นี้ให้ ImgBed site ของคุณ provide WebDAV access ให้ clients</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด admin panel แล้วไปที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="feature-นี้ทําอะไร" tabindex="-1">Feature นี้ทำอะไร <a class="header-anchor" href="#feature-นี้ทําอะไร" aria-label="Permalink to &quot;Feature นี้ทำอะไร&quot;">​</a></h2><p>หลัง WebDAV enabled ImgBed จะให้ fixed access URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>ใช้ URL นี้เพื่อ connect เข้า ImgBed file directory</p><p>Use cases ที่เหมาะ:</p><ul><li>Browse ImgBed files จาก computer file manager โดยตรง</li><li>Drag images เข้า WebDAV folder เพื่อ upload</li><li>Organize ImgBed folders จาก local file manager</li><li>ใช้ WebDAV-compatible software เพื่อ sync หรือ manage images</li><li>Access ImgBed content โดยไม่ต้องเปิด admin panel</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>เปิด WebDAV endpoint</p><p>เมื่อ disabled clients จะ connect ผ่าน WebDAV ไม่ได้</p><h3 id="username-และ-password" tabindex="-1">Username และ Password <a class="header-anchor" href="#username-และ-password" aria-label="Permalink to &quot;Username และ Password&quot;">​</a></h3><p>Credentials นี้ใช้เมื่อ WebDAV clients connect</p><p>ใช้ dedicated WebDAV username และ password อย่า reuse admin password หรือ upload password</p><p>ถ้า username หรือ password ว่าง WebDAV clients จะ connect ได้ไม่ถูกต้อง</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode ตัดสินว่า WebDAV clients จะ prefer image URL แบบใดเมื่ออ่าน images</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed เลือกตาม context เหมาะกับ normal use</td></tr><tr><td>Original</td><td>Prefer original images</td></tr><tr><td>Thumbnail</td><td>Prefer thumbnails เหมาะกับ fast preview</td></tr></tbody></table><p>ถ้าไม่แน่ใจ ให้ใช้ <code>Smart loading</code></p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel ใช้สำหรับ WebDAV uploads</p><p>เมื่อ copy files เข้า WebDAV directory จาก Windows หรือ client อื่น ImgBed จะ upload ผ่าน selected default upload channel</p><p>ถ้าไม่เลือก default channel การ browse อาจทำงานได้ แต่ uploads อาจ fail</p><h2 id="เข้าถึง-webdav-ใน-windows-11" tabindex="-1">เข้าถึง WebDAV ใน Windows 11 <a class="header-anchor" href="#เข้าถึง-webdav-ใน-windows-11" aria-label="Permalink to &quot;เข้าถึง WebDAV ใน Windows 11&quot;">​</a></h2><p>Windows 11 เพิ่ม WebDAV เป็น network location ได้</p><ol><li>เปิด <code>This PC</code></li><li>เลือก <code>Add a network location</code></li><li>ใส่ <code>https://your-domain.com/dav</code></li><li>เมื่อมี prompt ให้ใส่ WebDAV username และ password</li><li>ทำ wizard ให้เสร็จ จากนั้นเปิด WebDAV directory ใน File Explorer ได้</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>หลังเพิ่มแล้ว WebDAV directory จะแสดงใน Windows File Explorer คุณสามารถ open, copy และ manage files เหมือน folder ปกติ</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>หลัง WebDAV connection สำเร็จ โดยทั่วไปทำได้:</p><ul><li>View files และ folders</li><li>Upload files</li><li>Create folders</li><li>Rename files หรือ folders</li><li>Move files</li><li>Delete files</li></ul><p>WebDAV เหมาะกับ everyday access และ small-scale file management สำหรับ large moves, bulk deletes หรือ organization ที่ซับซ้อน แนะนำใช้ admin panel</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections จะแสดงใน WebDAV tab ของ Login Device Management ด้วย</p><p>คุณสามารถ review WebDAV clients และ force old devices offline เมื่อจำเป็น</p><p>ถ้าเปลี่ยน WebDAV username หรือ password clients เก่าต้อง sign in ใหม่</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-ถาม-username-และ-password-ซ้ํา" tabindex="-1">Windows ถาม Username และ Password ซ้ำ <a class="header-anchor" href="#windows-ถาม-username-และ-password-ซ้ํา" aria-label="Permalink to &quot;Windows ถาม Username และ Password ซ้ำ&quot;">​</a></h3><p>ตรวจว่า:</p><ul><li>URL คือ <code>https://your-domain.com/dav</code></li><li>Username และ password ตรงกับ WebDAV settings</li><li>WebDAV enabled</li><li>Site access ผ่าน HTTPS ได้</li></ul><h3 id="browsing-ได้-แต่-upload-fail" tabindex="-1">Browsing ได้ แต่ Upload fail <a class="header-anchor" href="#browsing-ได้-แต่-upload-fail" aria-label="Permalink to &quot;Browsing ได้ แต่ Upload fail&quot;">​</a></h3><p>ตรวจ <code>Default channel</code></p><p>WebDAV uploads ต้องใช้ default upload channel ถ้า missing, disabled หรือ misconfigured uploads อาจ fail</p><h3 id="access-speed-ไม่เสถียร" tabindex="-1">Access Speed ไม่เสถียร <a class="header-anchor" href="#access-speed-ไม่เสถียร" aria-label="Permalink to &quot;Access Speed ไม่เสถียร&quot;">​</a></h3><p>WebDAV performance ขึ้นกับ client, network, file count และ default upload channel</p><p>ถ้า directory มี files จำนวนมาก ให้จัดเป็น folders แทนการเก็บทุกอย่างใน directory เดียว</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>ใช้ HTTPS สำหรับ WebDAV access</li><li>ตั้ง strong password</li><li>อย่า share WebDAV password กับคนที่ไม่ trusted</li><li>ปิด WebDAV เมื่อไม่ได้ใช้งาน</li><li>Clean up unused WebDAV devices เป็นระยะใน Login Device Management</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients ไม่ใช้ large-file chunking flow ของ browser upload page สำหรับ files ที่ใหญ่กว่า suggested limits ด้านล่าง ให้ใช้ web upload page แทน</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
